  ('judicial-57f41407-moex-00161', 'judicial-57f41407', 'judicial-57f41407-moex-114-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '某市政府環境保護局查獲Ａ化學工廠管線洩漏，污染地下水，經環境保護局作成命其限期一個月改善，屆 期仍未改善者將予以依法裁罰。但於改善期限未屆滿前，即對Ａ工廠予以裁罰。請問該裁罰可能係違反下 列何項法律原則？', '["平等原則", "比例原則", "誠實信用原則", "不當聯結禁止原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "1b9e537fe27e", "answer_pdf_sha1": "ad1eaf69a973", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
